create extension if not exists pgcrypto;
create table if not exists platform_installation (id text primary key default 'default', installation_complete boolean not null default false, installed_version text, installed_at timestamptz, installed_by_user_id uuid, current_step text not null default 'welcome', license_status text not null default 'not_checked', bootstrap_generated boolean not null default false, metadata jsonb not null default '{}'::jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
insert into platform_installation (id) values ('default') on conflict (id) do nothing;
create table if not exists platform_install_drafts (id text primary key default 'default', draft jsonb not null default '{}'::jsonb, updated_at timestamptz not null default now());
create table if not exists encrypted_settings (id uuid primary key default gen_random_uuid(), key text not null unique, encrypted_value text not null, provider text not null default 'encrypted_db', last_four text, status text not null default 'configured', last_tested_at timestamptz, metadata jsonb not null default '{}'::jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists platform_license_settings (id text primary key default 'default', license_key text, license_status text not null default 'verification_disabled', license_plan text, license_holder text, license_expires_at timestamptz, validation_enabled boolean not null default false, verification_provider text, last_checked_at timestamptz, last_success_at timestamptz, last_error text, metadata jsonb not null default '{}'::jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
insert into platform_license_settings (id) values ('default') on conflict (id) do nothing;
create table if not exists app_users (id uuid primary key default gen_random_uuid(), full_name text not null, email text not null unique, phone text, active boolean not null default true, metadata jsonb not null default '{}'::jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists roles (id uuid primary key default gen_random_uuid(), key text not null unique, name text not null, description text, hierarchy int not null default 0, created_at timestamptz not null default now());
create table if not exists permissions (id uuid primary key default gen_random_uuid(), key text not null unique, label text not null, permission_group text not null, module_id text, created_at timestamptz not null default now());
create table if not exists role_permissions (role_key text not null, permission_key text not null, primary key(role_key, permission_key));
create table if not exists user_roles (user_id uuid not null, role_key text not null, primary key(user_id, role_key));
create table if not exists module_registry (id text primary key, name text not null, version text not null, enabled boolean not null default true, hidden boolean not null default false, beta boolean not null default false, experimental boolean not null default false, manifest jsonb not null default '{}'::jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists company_settings (id text primary key default 'default', settings jsonb not null default '{}'::jsonb, updated_at timestamptz not null default now());
create table if not exists theme_settings (id text primary key default 'default', settings jsonb not null default '{}'::jsonb, updated_at timestamptz not null default now());
create table if not exists homepage_settings (id text primary key default 'default', settings jsonb not null default '{}'::jsonb, updated_at timestamptz not null default now());
create table if not exists audit_logs (id uuid primary key default gen_random_uuid(), actor_user_id uuid, action text not null, entity_type text, entity_id text, metadata jsonb not null default '{}'::jsonb, created_at timestamptz not null default now());
